func (e Event) Cursor() pagination.Cursor {
	switch e.SortBy {
	case streaming.EventSortFieldIngestedAt:
		return pagination.NewCursor(e.IngestedAt, e.StoreRowID)
	case streaming.EventSortFieldStoredAt:
		return pagination.NewCursor(e.StoredAt, e.StoreRowID)
	default:
		return pagination.NewCursor(e.Time, e.StoreRowID)
	}
}

func (m *Manager) createNamespace(ctx context.Context, name string) error {
	var errs []error
	m.mu.RLock()
	defer m.mu.RUnlock()
	for _, handler := range m.config.Handlers {
		if err := handler.CreateNamespace(ctx, name); err != nil {
			errs = append(errs, err)
		}
	}
	return errors.Join(errs...)
}

func (i CreateTokenInput) Validate() error {
	var errs []error
	if i.Namespace == "" { errs = append(errs, fmt.Errorf("namespace is required")) }
	if i.Subject == "" { errs = append(errs, fmt.Errorf("subject is required")) }
	if i.ExpiresAt != nil && i.ExpiresAt.Before(time.Now()) {
		errs = append(errs, fmt.Errorf("expiration date must be in the future"))
	}
	if len(errs) > 0 { return errors.Join(errs...) }
	return nil
}
